import numpy as np
from sklearn.base import BaseEstimator, ClassifierMixin
from sklearn.ensemble import RandomForestClassifier
from sklearn.linear_model import LogisticRegression
from sklearn.neighbors import KNeighborsClassifier
from sklearn.svm import SVC

class EnsembleClassifier(BaseEstimator, ClassifierMixin):
    def __init__(self, base_estimators, voting='soft'):
        self.base_estimators = base_estimators
        self.voting = voting

    def fit(self, X, y):
        for estimator in self.base_estimators:
            estimator.fit(X, y)

    def predict(self, X):
        if self.voting == 'soft':
            probas = [estimator.predict_proba(X) for estimator in self.base_estimators]
            avg_proba = np.mean(probas, axis=0)
            return np.argmax(avg_proba, axis=1)
        elif self.voting == 'hard':
            predictions = [estimator.predict(X) for estimator in self.base_estimators]
            return np.round(np.mean(predictions, axis=0))

    def predict_proba(self, X):
        if self.voting == 'soft':
            probas = [estimator.predict_proba(X) for estimator in self.base_estimators]
            return np.mean(probas, axis=0)
        elif self.voting == 'hard':
            raise NotImplementedError("Probability estimates are not available for hard voting.")

